INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('mfl_loop_footprint_inverted_vs_theta', 'magnetic_flux_loop S4/S5/S6: the loop mesh''s own on-screen footprint is WIDEST at theta=90deg (edge-on/zero-flux) and NARROWEST at theta=0deg (face-on/max-flux) — visually backwards for "edge-on" on the S4 PRIMARY aha frame. The A.cos(theta) shadow and the Phi=0.00 readout both behave correctly, so the aha still lands through those, but the loop''s own silhouette may contradict them.', 'MODERATE', 'peter_parker:renderer_primitives', 'mflApplyPose() sets grp.rotation.y = radians(90 - thetaDeg) against a base loop-mesh geometry apparently authored face-on-to-camera at rotation=0 — this makes the mesh''s apparent screen width track (90-theta) rather than theta directly, so the mesh looks MORE open exactly when theta -> 90 (zero flux) and MORE tilted/narrow when theta -> 0 (max flux). NOT YET CONFIRMED as a defect vs a deliberate convention (possibly chosen so the theta-arc/normal-vector label stays legible against the camera) — eye-walker flagged this as genuinely ambiguous on the confirmation pass, pending founder/renderer_primitives review of whether the rotation formula should be inverted (e.g. rotation.y = radians(thetaDeg)) so the loop''s own footprint shrinks toward edge-on in the same direction as the shadow and the flux readout.', 'When a tilt mechanic drives a companion 2D shadow/projection specifically because the 3D mesh''s own screen footprint doesn''t legibly convey the tilt, verify the mesh''s own apparent size ALSO tracks the taught angle in the SAME direction as the shadow and the numeric readout — don''t rely on the shadow alone to carry the "edge-on" read. On any state combining a rotating mesh with a companion projection value, sample the mesh''s own screen-space bounding width at theta_range.min and theta_range.max and confirm it moves the same direction as the projection''s.', 'manual', 'On magnetic_flux_loop S4 dense frames, compare the loop mesh''s on-screen bounding-box width at theta=0 (theta_range.min) against theta=90 (theta_range.max) — founder/reviewer call: does "wider at edge-on" read as correct (deliberate camera framing) or backwards (rotation inversion)? If backwards, the fix is inverting the rotation.y formula in mflApplyPose so the loop''s own footprint collapses toward theta=90, matching the A.cos(theta) shadow and the Phi readout.', 'OPEN', ARRAY['magnetic_flux'], ARRAY[]::text[], 'session_2026-07-08_magnetic_flux_loop_confirmation_pass', 'incident')
